// UserBackground.tsx
import React from 'react';
import {StyleSheet, useWindowDimensions} from 'react-native';
import {Canvas, Circle} from '@shopify/react-native-skia';
function hash(s: string) { let h = 0; for (let i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) | 0; return Math.abs(h); }
export function UserBackground({userId}: {userId: string}) { const {width: SW, height: SH} = useWindowDimensions(); const seed = hash(userId); const circles: any[] = []; for (let i = 0; i < 8; i++) { const x = ((seed + i * 73) % SW); const y = ((seed * 7 + i * 113) % SH); circles.push({x, y, r: 30 + (seed % 50)}); } return (<Canvas style={StyleSheet.absoluteFill}>{circles.map((c, i) => <Circle key={i} cx={c.x} cy={c.y} r={c.r} color='rgba(10,132,255,0.1)'/>)}</Canvas>); }

