export function DiscoverableHandle() { const scale = useSharedValue(1); useEffect(() => { scale.value = withSequence(withSpring(1.3), withSpring(1), withSpring(1.3), withSpring(1)); }, []); const style = useAnimatedStyle(() => ({transform: [{scaleX: scale.value}]})); return <Animated.View style={[s.handle, style]}/>; }
