// BrandLoader.tsx
import React from 'react';
import {Canvas, Path, Skia} from '@shopify/react-native-skia';
import {useSharedValue, useDerivedValue, withRepeat, withTiming, Easing, interpolateColor} from 'react-native-reanimated';
import {StyleSheet, View} from 'react-native';
export function BrandLoader({size = 48}: {size?: number}) { const t = useSharedValue(0); React.useEffect(() => { t.value = withRepeat(withTiming(1, {duration: 1500, easing: Easing.linear}), -1, false); }, []); const color = useDerivedValue(() => interpolateColor(t.value, [0, 0.33, 0.66, 1], ['#FF3B5C', '#FFCC00', '#0A84FF', '#FF3B5C'])); const path = Skia.Path.MakeFromSVGString('M16 4 L28 28 L4 28 Z')!; return (<View style={{width: size, height: size}}><Canvas style={StyleSheet.absoluteFill}><Path path={path} color={color}/></Canvas></View>); }

