import React from 'react';
import {Pressable} from 'react-native';
import Animated, {useSharedValue, useAnimatedStyle, withSpring} from 'react-native-reanimated';
export function PressableCard({children, onPress}: {children: React.ReactNode; onPress: () => void}) { const scale = useSharedValue(1); const style = useAnimatedStyle(() => ({transform: [{scale: scale.value}]})); return (<Pressable onPressIn={() => { scale.value = withSpring(0.96, {damping: 14, stiffness: 280}); }} onPressOut={() => { scale.value = withSpring(1, {damping: 16, stiffness: 240}); }} onPress={onPress}><Animated.View style={style}>{children}</Animated.View></Pressable>); }

