// AuroraBg.tsx
import React from 'react';
import {StyleSheet, useWindowDimensions} from 'react-native';
import {Canvas, Rect, LinearGradient, vec} from '@shopify/react-native-skia';
import {useSharedValue, useFrameCallback, useDerivedValue} from 'react-native-reanimated';
export function AuroraBg() { const {width: SW, height: SH} = useWindowDimensions(); const t = useSharedValue(0); useFrameCallback(({timeSinceFirstFrame}) => { t.value = timeSinceFirstFrame / 1000; }); const grad = useDerivedValue(() => ({start: vec(0, Math.sin(t.value * 0.1) * 100), end: vec(SW, SH + Math.cos(t.value * 0.1) * 100)})); return (<Canvas style={StyleSheet.absoluteFill}><Rect x={0} y={0} width={SW} height={SH}><LinearGradient start={grad.value.start} end={grad.value.end} colors={['#0A1F3C', '#1A4D8C', '#30D158', '#0A84FF', '#0A1F3C']}/></Rect></Canvas>); }

